import React from "react";
import { FormControl, Select, MenuItem, FormHelperText, Box, CircularProgress, Autocomplete, TextField, Tooltip } from "@mui/material";
import FAWTypography from './FAWTypography';
import RequiredIndicator from './RequiredIndicator';
import { colors } from "../../utils/designTokens";

const GRID_NAVIGATION_KEYS = new Set([
    'ArrowUp', 'ArrowDown', 'ArrowLeft', 'ArrowRight',
    'Enter', 'Escape', ' ', 'Tab', 'Home', 'End', 'PageUp', 'PageDown',
]);
/** Stops navigation keys from reaching DataGrid parents; printable keys can reach listbox typeahead. */
export function stopDropdownKeydownBubblingToParents(e) {
    if (e.ctrlKey || e.metaKey || e.altKey) return;
    if (GRID_NAVIGATION_KEYS.has(e.key)) {
        e.stopPropagation();
    }
}

/**
 * MUI can leave focus on the combobox until the menu transition finishes; the first letter then
 * never hits MenuList typeahead and the menu often closes. After the paper mounts, move focus
 * into the listbox if focus is still on the combobox.
 */
function focusSelectListboxFromPaperIfNeeded(paperNode) {
    if (typeof document === 'undefined' || !paperNode) return;
    const tryMoveFocus = () => {
        let root = paperNode;
        if (!root.querySelector?.('[role="listbox"]')) {
            root = paperNode.closest?.('.MuiPaper-root') || paperNode;
        }
        if (!root.querySelector?.('[role="listbox"]')) {
            root = paperNode.closest?.('.MuiPopover-root') || root;
        }
        const ae = document.activeElement;
        if (!ae) return;
        const stillOnCombobox =
            ae.getAttribute('role') === 'combobox' ||
            (typeof ae.closest === 'function' && ae.closest('.MuiSelect-select'));
        if (!stillOnCombobox) return;
        const listbox = root.querySelector?.('[role="listbox"]');
        if (!listbox) return;
        const opt =
            listbox.querySelector('[role="option"][tabindex="0"]') ||
            listbox.querySelector('[role="option"]:not([aria-disabled="true"])');
        opt?.focus?.();
    };
    requestAnimationFrame(tryMoveFocus);
    setTimeout(tryMoveFocus, 0);
}

/**
 * Capture phase: printable keys should run MenuList typeahead. DataGrid / editor wrappers often keep
 * focus on a parent Box while the menu is open; event.target.closest(combobox) is then null (combobox
 * is not an ancestor of the focused node). Resolve combobox from this component root (currentTarget)
 * and only skip when focus is already inside the portaled listbox.
 */
function handleSelectPrintableKeyWhileMenuOpenCapture(e) {
    if (e.ctrlKey || e.metaKey || e.altKey) return;
    if (e.key === ' ' || e.key.length !== 1) return;

    const root = e.currentTarget;
    if (!root?.querySelector) return;

    const combobox = root.querySelector('[role="combobox"]');
    if (!combobox || combobox.getAttribute('aria-expanded') !== 'true') return;

    const listboxId = combobox.getAttribute('aria-controls');
    if (!listboxId) return;

    const menuListbox = typeof document !== 'undefined' ? document.getElementById(listboxId) : null;
    const ae = typeof document !== 'undefined' ? document.activeElement : null;
    if (menuListbox && ae && menuListbox.contains(ae)) {
        // Focus already in the open menu (portal); let MUI handle typeahead / navigation
        return;
    }

    const key = e.key;
    const code = e.code;
    let handled = false;

    const tryFocusListboxAndDispatchTypeahead = () => {
        if (handled) return true;
        if (combobox.getAttribute('aria-expanded') !== 'true') return false;
        const listbox = document.getElementById(listboxId);
        if (!listbox) return false;
        const opt =
            listbox.querySelector('[role="option"][tabindex="0"]') ||
            listbox.querySelector('[role="option"]:not([aria-disabled="true"])');
        if (!opt) return false;
        handled = true;
        opt.focus();
        requestAnimationFrame(() => {
            listbox.dispatchEvent(
                new KeyboardEvent('keydown', {
                    key,
                    code,
                    bubbles: true,
                    cancelable: true,
                })
            );
        });
        return true;
    };

    if (tryFocusListboxAndDispatchTypeahead()) {
        e.preventDefault();
        e.stopPropagation();
        return;
    }

    e.preventDefault();
    e.stopPropagation();
    requestAnimationFrame(() => {
        requestAnimationFrame(() => {
            tryFocusListboxAndDispatchTypeahead();
        });
    });
    setTimeout(() => {
        tryFocusListboxAndDispatchTypeahead();
    }, 0);
}

const FAWDropdown = React.memo(({ label, id, value, defaultValue, options = [], onChange, name, error, helperText, loading = false, required, placeholder, labelSx, searchable = false, MenuProps: menuPropsProp, SelectDisplayProps: selectDisplayPropsProp, onOpen: onOpenProp, onClose: onCloseProp, ...rest }) => {
    // Non-empty options only in the menu (placeholder row with value '' is excluded). If the current
    // value is not in that set, MUI logs "out-of-range" and may render no options — keyboard typeahead breaks.
    const selectMenuOptions = React.useMemo(() => {
        const base = (options || []).filter((opt) => opt.value !== '');
        const raw =
            value !== undefined && value !== null && value !== ''
                ? value
                : defaultValue !== undefined && defaultValue !== null && defaultValue !== ''
                  ? defaultValue
                  : null;
        if (raw === null || raw === '') {
            return base;
        }
        if (base.some((opt) => String(opt.value) === String(raw))) {
            return base;
        }
        return [...base, { value: raw, label: String(raw) }];
    }, [options, value, defaultValue]);

    // Support both controlled and uncontrolled usage
    const handleChange = (e) => {
        const selectedValue = e.target.value;
        const selectedOption = selectMenuOptions.find((opt) => String(opt.value) === String(selectedValue));
        if (typeof onChange === "function") {
            onChange(selectedOption, e);
        }
    };

    // Determine placeholder text: use prop if provided, otherwise check for placeholder option, or use default
    const hasPlaceholderOption = options.length > 0 && options[0].value === '';
    const placeholderText = placeholder || (hasPlaceholderOption ? options[0].label : '-- Select --');

    // For searchable functionality, use Autocomplete
    if (searchable) {
        return (
            <div style={{ position: 'relative', zIndex: 1 }}>
                {label && (
                    <FAWTypography
                        variant="body2"
                        component="label"
                        htmlFor={id}
                        sx={{
                            display: "block",
                            marginBottom: "4px",
                            fontWeight: "500",
                            fontSize: "14px",
                            ...labelSx
                        }}
                    >
                        <Box component="span" sx={{ display: 'inline-flex', alignItems: 'baseline' }}>
                            {label}
                            <RequiredIndicator required={required} />
                        </Box>
                    </FAWTypography>
                )}
                <Autocomplete
                    id={id}
                    name={name || id}
                    options={options}
                    value={(typeof value === 'object' && value) ? value : (options.find(opt => opt.value === value) || null)}
                    onChange={(event, newValue) => {
                        if (typeof onChange === "function") {
                            onChange(newValue, event);
                        }
                    }}
                    getOptionLabel={(option) => option.label || ""}
                    isOptionEqualToValue={(option, value) => option.value === value.value}
                    disableScrollLock={true}
                    filterOptions={(options, { inputValue }) => {
                        // If no input value, return all options
                        if (!inputValue || inputValue.trim() === '') {
                            return options;
                        }

                        const searchTerm = inputValue.toLowerCase().trim();

                        // Filter options that match the search term in label
                        return options.filter(option =>
                            option.label && option.label.toLowerCase().includes(searchTerm)
                        );
                    }}
                    fullWidth={rest.fullWidth !== false}
                    size="small"
                    freeSolo={false}
                    disabled={loading || rest.disabled}
                    loading={loading}
                    renderOption={(props, option) => (
                        <li
                            {...props}
                            key={option.value}
                            style={{
                                color: colors.type.default,
                                fontSize: '14px',
                                padding: '12px 16px'
                            }}
                        >
                            <Tooltip
                                title={option.label || ''}
                                placement="left"
                                arrow
                                enterDelay={500}
                                disableInteractive
                                PopperProps={{ style: { zIndex: 100002 } }}
                            >
                                <span style={{ display: 'block', overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>
                                    {option.label}
                                </span>
                            </Tooltip>
                        </li>
                    )}
                    renderInput={(params) => (
                        <TextField
                            {...params}
                            placeholder={placeholderText}
                            variant="outlined"
                            fullWidth
                            error={!!error}
                            helperText={helperText}
                            InputProps={{
                                ...params.InputProps,
                                endAdornment: (
                                    <>
                                        {loading ? <CircularProgress color="inherit" size={20} /> : null}
                                        {params.InputProps.endAdornment}
                                    </>
                                ),
                            }}
                            sx={{
                                '& .MuiOutlinedInput-root': {
                                    fontSize: '1.1rem',
                                    '& .MuiOutlinedInput-input': {
                                        paddingTop: '8px !important',
                                        paddingBottom: '8px !important',
                                    },
                                },
                                ...rest.sx
                            }}
                        />
                    )}
                    sx={{
                        '& .MuiAutocomplete-paper': {
                            borderRadius: '8px',
                            boxShadow: '0 4px 20px rgba(0,0,0,0.1)',
                        },
                        '& .MuiAutocomplete-option': {
                            padding: '12px 16px',
                            fontSize: '14px',
                            color: colors.type.default,
                            '&:hover': {
                                backgroundColor: colors.background.secondary,
                            },
                            '&[aria-selected="true"]': {
                                backgroundColor: colors.background.selected,
                                color: colors.type.default,
                                '&:hover': {
                                    backgroundColor: colors.background.selected,
                                },
                            },
                        },
                        ...rest.sx
                    }}
                    {...rest}
                />
            </div>
        );
    }

    // For non-searchable, use regular Select
    return (
        <div
            style={{ position: 'relative', zIndex: 1, width: '100%' }}
            onKeyDownCapture={handleSelectPrintableKeyWhileMenuOpenCapture}
            onKeyDown={stopDropdownKeydownBubblingToParents}
        >
            {label && (
                <FAWTypography
                    variant="body2"
                    component="label"
                    htmlFor={id}
                    sx={{
                        display: "block",
                        marginBottom: "4px",
                        fontWeight: "500",
                        fontSize: "14px",
                        ...labelSx
                    }}
                >
                    <Box component="span" sx={{ display: 'inline-flex', alignItems: 'baseline' }}>
                        {label}
                        <RequiredIndicator required={required} />
                    </Box>
                </FAWTypography>
            )}
            <FormControl fullWidth={rest.fullWidth !== false} variant="outlined" disabled={rest.disabled || false} error={!!error} sx={{ width: '100%', minWidth: 0 }}>
                <Select
                    id={id}
                    name={name || id}
                    value={value}
                    defaultValue={defaultValue}
                    onChange={handleChange}
                    displayEmpty
                    disabled={loading || rest.disabled}
                    renderValue={(selected) => {
                        if (loading) {
                            return (
                                <Box sx={{ display: 'flex', alignItems: 'center', gap: 1, width: '100%', minWidth: 0, overflow: 'hidden', textOverflow: 'ellipsis' }}>
                                    <CircularProgress size={16} />
                                    <FAWTypography color="textSecondary" sx={{ overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap', flex: 1, minWidth: 0 }}>
                                        Loading...
                                    </FAWTypography>
                                </Box>
                            );
                        }
                        if (!selected || selected === '') {
                            return (
                                <FAWTypography color="textSecondary" sx={{ overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap', width: '100%', minWidth: 0 }}>
                                    {placeholderText}
                                </FAWTypography>
                            );
                        }
                        // Find the selected option and return its label (includes synthetic orphan row)
                        const selectedOption = selectMenuOptions.find(opt => String(opt.value) === String(selected));
                        const displayText = selectedOption ? selectedOption.label : selected;
                        return (
                            <FAWTypography sx={{ overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap', width: '100%', minWidth: 0 }}>
                                {displayText}
                            </FAWTypography>
                        );
                    }}
                    {...rest}
                    onOpen={onOpenProp}
                    onClose={onCloseProp}
                    SelectDisplayProps={selectDisplayPropsProp}
                    sx={{
                        width: '100% !important',
                        minWidth: 0,
                        maxWidth: '100%',
                        '.MuiSelect-select': {
                            fontSize: '1.1rem',
                            paddingTop: '8px !important',
                            paddingBottom: '8px !important',
                            display: 'flex',
                            alignItems: 'center',
                            width: '100% !important',
                            minWidth: 0,
                            maxWidth: '100%',
                            overflow: 'hidden',
                            textOverflow: 'ellipsis',
                            whiteSpace: 'nowrap'
                        },
                        '& .MuiOutlinedInput-root': {
                            width: '100% !important',
                            minWidth: 0
                        },
                        ...rest.sx
                    }}
                    MenuProps={{
                        ...menuPropsProp,
                        TransitionProps: {
                            ...menuPropsProp?.TransitionProps,
                            onEntered: (node, isAppearing) => {
                                menuPropsProp?.TransitionProps?.onEntered?.(node, isAppearing);
                                focusSelectListboxFromPaperIfNeeded(node);
                            },
                        },
                        PaperProps: {
                            ...menuPropsProp?.PaperProps,
                            sx: {
                                zIndex: 100000,
                                ...menuPropsProp?.PaperProps?.sx,
                            },
                        },
                        style: {
                            zIndex: 100000,
                            ...menuPropsProp?.style,
                        },
                        MenuListProps: {
                            ...menuPropsProp?.MenuListProps,
                            onKeyDown: (e) => {
                                menuPropsProp?.MenuListProps?.onKeyDown?.(e);
                                e.stopPropagation();
                            },
                        },
                    }}
                >
                    {loading ? (
                        <MenuItem disabled>
                            <Box sx={{ display: 'flex', alignItems: 'center', gap: 1, width: '100%' }}>
                                <CircularProgress size={16} />
                                <FAWTypography color="textSecondary">
                                    Loading options...
                                </FAWTypography>
                            </Box>
                        </MenuItem>
                    ) : (
                        selectMenuOptions.map((opt, idx, filteredOptions) => (
                                <MenuItem
                                    key={`${opt.value}_${idx}`}
                                    value={opt.value}
                                    sx={{
                                        backgroundColor: colors.background.default,
                                        fontSize: '14px',
                                        padding: '12px 16px',
                                        ...(idx === 0 && {
                                            borderTopLeftRadius: '8px',
                                            borderTopRightRadius: '8px'
                                        }),
                                        ...(idx === filteredOptions.length - 1 && {
                                            borderBottomLeftRadius: '8px',
                                            borderBottomRightRadius: '8px'
                                        }),
                                        '&:hover': {
                                            backgroundColor: colors.background.secondary
                                        },
                                        '&.Mui-selected': {
                                            backgroundColor: colors.background.selected,
                                            color: colors.type.default,
                                            '&:hover': {
                                                backgroundColor: colors.background.selected
                                            }
                                        }
                                    }}
                                >
                                    <Tooltip
                                        title={opt.label || ''}
                                        placement="left"
                                        arrow
                                        enterDelay={500}
                                        disableInteractive
                                        disableFocusListener
                                        PopperProps={{ style: { zIndex: 100002 } }}
                                    >
                                        <span style={{ display: 'block', overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>
                                            {opt.label}
                                        </span>
                                    </Tooltip>
                                </MenuItem>
                            ))
                    )}
                </Select>
                {helperText && (
                    <FormHelperText error={!!error}>
                        {helperText}
                    </FormHelperText>
                )}
            </FormControl>
        </div>
    );
});

export default FAWDropdown; 